/**
 * @fileoverview LayoutEditor events — centralised event binding for the
 *               toolbar, canvas (pointer / wheel / drag-drop / dblclick),
 *               keyboard shortcuts, context menu, fullscreen, panel
 *               toggle, and delegated view events (layer panel, props,
 *               palette, isolation bar, text-content input).
 *
 * Every exported function receives the thin `ctx` context object produced
 * by the class's `#ctx()` bridge (see index.js).
 *
 * @module module/LayoutEditor/events
 */

import razyui from '../../index.js';
import { MIN_ELEMENT_SIZE, BUILTIN_PALETTE_ITEMS } from './constants.js';
import { el, esc, normRect, findEl, findParentGroup, getGroupDescendants, computeGuides } from './helpers.js';

// ═══════════════════════════════════════════════
// Toolbar
// ═══════════════════════════════════════════════

/**
 * Bind click handlers on the toolbar and panel chrome.
 * @param {Object} ctx
 */
export function bindToolbar(ctx) {
    // Panel close buttons & floating tabs
    ctx.canvas.on('click', (e) => {
        const target = razyui(e.target);
        const closeBtn = target.closest('.le-panel-close');
        if (closeBtn.length) {
            const action = closeBtn.data('action');
            if (action) togglePanel(action, ctx);
            return;
        }
        const tab = target.closest('.le-panel-tab');
        if (tab.length) {
            const panelName = tab.data('panelTab');
            if (panelName) togglePanel(panelName, ctx);
            return;
        }
        // Left panel tab switching (Layers / Elements)
        const leftTab = target.closest('.le-left-tab');
        if (leftTab.length) {
            const which = leftTab.data('leftTab');
            ctx.layerPanel.find('.le-left-tab').each(t => razyui(t).toggleClass('is-active', t === leftTab[0]));
            ctx.layerPanel.find('.le-left-content').each(c => {
                razyui(c).toggleClass('is-active', razyui(c).hasClass(which === 'layers' ? 'le-left-layers' : 'le-left-elements'));
            });
        }
    });

    ctx.toolbar.on('click', (e) => {
        const btn = razyui(e.target).closest('[data-action]');
        if (!btn.length) return;
        const action = btn.data('action');
        if (action === 'undo')       ctx.undo();
        else if (action === 'redo')       ctx.redo();
        else if (action === 'zoom-in')    ctx.setZoom(ctx.zoom + 0.1);
        else if (action === 'zoom-out')   ctx.setZoom(ctx.zoom - 0.1);
        else if (action === 'zoom-fit')   ctx.fitToView();
        else if (action === 'grid')       ctx.toggleGrid();
        else if (action === 'group')      ctx.groupSelected();
        else if (action === 'ungroup')    ctx.ungroupSelected();
        else if (action === 'fullscreen') toggleFullscreen(ctx);
        else if (action === 'layers')     togglePanel('layers', ctx);
        else if (action === 'props')      togglePanel('props', ctx);
        else if (action === 'export')     ctx.exportJSON();
    });
}

// ═══════════════════════════════════════════════
// Fullscreen / panel toggle
// ═══════════════════════════════════════════════

/**
 * Toggle fullscreen mode on the editor container.
 * @param {Object} ctx
 */
function toggleFullscreen(ctx) {
    const $container = razyui(ctx.container);
    $container.toggleClass('le-fullscreen');
    const isFS = $container.hasClass('le-fullscreen');
    const btn = ctx.toolbar.find('[data-action="fullscreen"]');
    if (btn.length) btn.toggleClass('le-tb-active', isFS);
    // Listen for Escape to exit fullscreen
    if (isFS) {
        const escOpts = ctx.signal ? { capture: true, signal: ctx.signal } : { capture: true };
        const escHandler = (e) => {
            if (e.key === 'Escape' && $container.hasClass('le-fullscreen')) {
                $container.removeClass('le-fullscreen');
                if (btn.length) btn.removeClass('le-tb-active');
                document.removeEventListener('keydown', escHandler, true);
                ctx.centerArtboard();
            }
        };
        document.addEventListener('keydown', escHandler, escOpts);
    }
    // Re-center after layout change
    requestAnimationFrame(() => ctx.centerArtboard());
}

/**
 * Toggle visibility of a panel (layers or props).
 * @param {string} panelName
 * @param {Object} ctx
 */
function togglePanel(panelName, ctx) {
    if (panelName === 'palette') panelName = 'layers'; // palette is now part of left panel
    const panel = panelName === 'layers' ? ctx.layerPanel : ctx.propPanel;
    const btn = ctx.toolbar.find(`[data-action="${panelName}"]`);
    const tab = ctx.canvas.find(`[data-panel-tab="${panelName}"]`);
    const isVisible = !panel.hasClass('le-panel-hidden');
    panel.toggleClass('le-panel-hidden', isVisible);
    if (btn.length) btn.toggleClass('le-tb-active', !isVisible);
    if (tab.length) tab.toggleClass('le-panel-tab-hidden', !isVisible);
}

// ═══════════════════════════════════════════════
// Canvas interaction (pointer / wheel / dnd)
// ═══════════════════════════════════════════════

/**
 * Bind pointer, wheel, drag-drop and dblclick events on the canvas.
 * @param {Object} ctx
 */
export function bindCanvas(ctx) {
    // Pointer events
    ctx.canvas.on('pointerdown', (e) => onPointerDown(e, ctx));
    ctx.canvas.on('pointermove', (e) => onPointerMove(e, ctx));
    ctx.canvas.on('pointerup',   (e) => onPointerUp(e, ctx));

    // Zoom
    ctx.canvas.on('wheel', (e) => {
        const target = razyui(e.target);
        if (target.closest('.le-layers').length || target.closest('.le-props').length) return;
        e.preventDefault();
        const delta = e.deltaY > 0 ? -0.05 : 0.05;
        ctx.setZoom(ctx.zoom + delta, e.clientX, e.clientY);
    }, { passive: false });

    // Custom context menu
    ctx.canvas.on('contextmenu', (e) => {
        e.preventDefault();
        showContextMenu(e, ctx);
    });

    // Drag-drop from palette
    ctx.canvas.on('dragover', (e) => {
        if (e.dataTransfer.types.includes('text/le-element') || e.dataTransfer.types.includes('text/le-plugin')) {
            e.preventDefault();
            e.dataTransfer.dropEffect = 'copy';
        }
    });
    ctx.canvas.on('drop', (e) => {
        e.preventDefault();
        const pos = ctx.clientToArtboard(e.clientX, e.clientY);
        const builtinType = e.dataTransfer.getData('text/le-element');
        const pluginName  = e.dataTransfer.getData('text/le-plugin');
        if (builtinType) {
            ctx.addElement(builtinType, { x: pos.x - 60, y: pos.y - 30 });
        } else if (pluginName) {
            const plugin = ctx.plugins.find(p => p.name === pluginName);
            if (plugin) {
                const d = plugin.defaults || {};
                const created = ctx.addPluginElement(plugin);
                created.x = pos.x - (d.w || 200) / 2;
                created.y = pos.y - (d.h || 100) / 2;
                ctx.renderElement(created);
            }
        }
    });

    // Double-click to edit text or enter group isolation
    ctx.artboard.on('dblclick', async (e) => {
        const elDom = razyui(e.target).closest('.le-element');
        if (!elDom.length) return;
        const elData = findEl(elDom.data('leId'), ctx.elements);
        if (elData?.type === 'group') {
            ctx.enterIsolation(elData);
            return;
        }
        if (elData?.type === 'text') {
            const content = elDom.find('.le-el-content')[0];
            content.focus();
        }
        if (elData?.type === 'image') {
            const Dialog = await razyui.load('Dialog');
            const url = await Dialog.prompt('Image URL', 'Enter image URL:', { defaultValue: elData.content || '' });
            if (url !== null) {
                ctx.pushUndo();
                elData.content = url;
                ctx.renderElement(elData);
                ctx.refreshProps();
                ctx.onChange();
            }
        }
    });
}

// ── Pointer handlers ──

function onPointerDown(e, ctx) {
    ctx.closeColorPopups();
    hideContextMenu(ctx);
    // Ignore events inside floating panels
    const target = razyui(e.target);
    if (target.closest('.le-layers').length || target.closest('.le-props').length || target.closest('.le-panel-tab').length || target.closest('.le-iso-bar').length) return;

    // Middle-click or Alt+click: pan
    if (e.button === 1 || (e.button === 0 && e.altKey)) {
        ctx.isPanning = true;
        ctx.panStart = { x: e.clientX - ctx.panX, y: e.clientY - ctx.panY };
        ctx.canvas.css('cursor', 'grabbing');
        e.preventDefault();
        return;
    }

    // Check if clicking a handle (resize)
    const handle = target.closest('.le-handle');
    if (handle.length) {
        const elDom = handle.closest('.le-element');
        const elData = findEl(elDom.data('leId'), ctx.elements);
        if (elData && !elData.locked) {
            ctx.isResizing = true;
            ctx.resizeHandle = handle.data('handle');
            ctx.resizeStart = { el: { ...elData }, mx: e.clientX, my: e.clientY };
            e.preventDefault();
            e.stopPropagation();
        }
        return;
    }

    // Check if clicking an element (drag)
    const elDom = target.closest('.le-element');
    if (elDom.length) {
        let elId = elDom.data('leId');
        let elData = findEl(elId, ctx.elements);
        // Isolation mode logic
        if (ctx.isolationGroup) {
            const isChild = ctx.isolationGroup.children?.includes(elId);
            if (!isChild && elId !== ctx.isolationGroup.id) return;
        } else {
            // Normal mode: if child of group, select group instead
            const parentGroup = findParentGroup(elId, ctx.elements);
            if (parentGroup) {
                elId = parentGroup.id;
                elData = parentGroup;
            }
        }
        if (elData && !elData.locked) {
            if (!ctx.selected.has(elId)) {
                ctx.toggleSelect(elId, e.shiftKey || e.ctrlKey || e.metaKey);
            }
            ctx.isDragging = true;
            ctx.pushUndo();
            const canvasPos = ctx.clientToArtboard(e.clientX, e.clientY);
            ctx.dragStart = canvasPos;
            ctx.dragOffsets = {};
            // Collect drag offsets for selected items AND their group children
            const allDragIds = new Set();
            ctx.selected.forEach(id => {
                allDragIds.add(id);
                const selEl = findEl(id, ctx.elements);
                if (selEl?.type === 'group') {
                    getGroupDescendants(selEl, ctx.elements).forEach(cid => allDragIds.add(cid));
                }
            });
            allDragIds.forEach(id => {
                const sel = findEl(id, ctx.elements);
                if (sel) ctx.dragOffsets[id] = { dx: sel.x - canvasPos.x, dy: sel.y - canvasPos.y };
            });
            e.preventDefault();
        }
        return;
    }

    // Click on empty artboard → rubber-band selection
    if (e.target === ctx.artboard[0] || razyui(e.target).hasClass('le-grid-overlay') || e.target === ctx.guidesOverlay[0]) {
        if (!e.shiftKey && !e.ctrlKey && !e.metaKey) {
            ctx.setSelected([]);
        }
        ctx.isSelecting = true;
        const pos = ctx.clientToArtboard(e.clientX, e.clientY);
        ctx.selectRect = { x: pos.x, y: pos.y, w: 0, h: 0 };
        ctx.selectionBox.css({
            left: pos.x + 'px', top: pos.y + 'px',
            width: '0px', height: '0px', display: 'block',
        });
        e.preventDefault();
        return;
    }

    // Click on canvas outside artboard → pan start
    ctx.isPanning = true;
    ctx.panStart = { x: e.clientX - ctx.panX, y: e.clientY - ctx.panY };
    ctx.canvas.css('cursor', 'grabbing');
}

function onPointerMove(e, ctx) {
    if (ctx.isPanning) {
        ctx.panX = e.clientX - ctx.panStart.x;
        ctx.panY = e.clientY - ctx.panStart.y;
        ctx.applyTransform();
        return;
    }

    if (ctx.isDragging && ctx.dragStart) {
        const pos = ctx.clientToArtboard(e.clientX, e.clientY);
        // Move all elements in dragOffsets (includes group children)
        for (const id of Object.keys(ctx.dragOffsets)) {
            const elData = findEl(id, ctx.elements);
            if (!elData || elData.locked) continue;
            const off = ctx.dragOffsets[id];
            elData.x = pos.x + off.dx;
            elData.y = pos.y + off.dy;

            // Grid snap (only for selected, not children)
            if (ctx.snapToGrid && ctx.selected.has(id)) {
                elData.x = Math.round(elData.x / ctx.gridSize) * ctx.gridSize;
                elData.y = Math.round(elData.y / ctx.gridSize) * ctx.gridSize;
            }
        }
        // Smart guides (use first selected)
        const firstId = [...ctx.selected][0];
        if (firstId) computeGuides(firstId, ctx);

        // Render all dragged elements
        for (const id of Object.keys(ctx.dragOffsets)) {
            const elData = findEl(id, ctx.elements);
            if (elData) ctx.renderElement(elData);
        }
        ctx.refreshGuides();
        ctx.updatePropValues();
        return;
    }

    if (ctx.isResizing && ctx.resizeStart) {
        const dx = (e.clientX - ctx.resizeStart.mx) / ctx.zoom;
        const dy = (e.clientY - ctx.resizeStart.my) / ctx.zoom;
        const orig = ctx.resizeStart.el;
        const elData = findEl(orig.id, ctx.elements);
        if (!elData) return;

        const h = ctx.resizeHandle;
        // W/E edges
        if (h.includes('e')) { elData.w = Math.max(MIN_ELEMENT_SIZE, orig.w + dx); }
        if (h.includes('w')) { elData.x = orig.x + dx; elData.w = Math.max(MIN_ELEMENT_SIZE, orig.w - dx); }
        // N/S edges
        if (h.includes('s')) { elData.h = Math.max(MIN_ELEMENT_SIZE, orig.h + dy); }
        if (h.includes('n')) { elData.y = orig.y + dy; elData.h = Math.max(MIN_ELEMENT_SIZE, orig.h - dy); }

        ctx.renderElement(elData);
        ctx.updatePropValues();
        return;
    }

    if (ctx.isSelecting && ctx.selectRect) {
        const pos = ctx.clientToArtboard(e.clientX, e.clientY);
        ctx.selectRect.w = pos.x - ctx.selectRect.x;
        ctx.selectRect.h = pos.y - ctx.selectRect.y;
        const { x, y, w, h } = normRect(ctx.selectRect);
        ctx.selectionBox.css({
            left: x + 'px', top: y + 'px',
            width: w + 'px', height: h + 'px',
        });
        return;
    }

    // Hover effect
    const elDom = razyui(e.target).closest('.le-element');
    if (elDom.length) {
        const id = elDom.data('leId');
        if (ctx.hoveredId !== id) {
            ctx.artboard.find('.le-hovered').each(d => razyui(d).removeClass('le-hovered'));
            elDom.addClass('le-hovered');
            ctx.hoveredId = id;
        }
    } else if (ctx.hoveredId) {
        ctx.artboard.find('.le-hovered').each(d => razyui(d).removeClass('le-hovered'));
        ctx.hoveredId = null;
    }
}

function onPointerUp(e, ctx) {
    if (ctx.isPanning) {
        ctx.isPanning = false;
        ctx.canvas.css('cursor', '');
        return;
    }

    if (ctx.isDragging) {
        ctx.isDragging = false;
        ctx.clearGuides();
        ctx.onChange();
        return;
    }

    if (ctx.isResizing) {
        ctx.isResizing = false;
        ctx.resizeHandle = null;
        ctx.resizeStart = null;
        ctx.onChange();
        return;
    }

    if (ctx.isSelecting) {
        ctx.isSelecting = false;
        ctx.selectionBox.css('display', 'none');
        // Compute selection
        const { x, y, w, h } = normRect(ctx.selectRect);
        if (w > 3 || h > 3) {
            const ids = ctx.elements.filter(el => {
                return el.visible && !el.locked &&
                    el.x < x + w && el.x + el.w > x &&
                    el.y < y + h && el.y + el.h > y;
            }).map(el => el.id);
            ctx.setSelected(ids);
        }
        ctx.selectRect = null;
        return;
    }
}

// ═══════════════════════════════════════════════
// Keyboard shortcuts
// ═══════════════════════════════════════════════

/**
 * Bind global keyboard shortcuts for the editor.
 * @param {Object} ctx
 */
export function bindKeyboard(ctx) {
    const opts = ctx.signal ? { signal: ctx.signal } : undefined;
    razyui(document).on('keydown', (e) => {
        // Check if editor is target context
        const inEditor = ctx.container.contains(document.activeElement) || ctx.container.contains(e.target) || document.activeElement === document.body;
        if (!inEditor) return;
        // Don't capture when typing in contenteditable or input
        if (razyui(e.target).closest('[contenteditable="true"]').length || e.target.tagName === 'INPUT' || e.target.tagName === 'SELECT' || e.target.tagName === 'TEXTAREA') return;

        const ctrl = e.ctrlKey || e.metaKey;

        if (e.key === 'Delete' || e.key === 'Backspace') {
            if (ctx.selected.size) {
                ctx.removeElements([...ctx.selected]);
                e.preventDefault();
            }
        }
        else if (ctrl && e.key === 'z') { ctx.undo(); e.preventDefault(); }
        else if (ctrl && (e.key === 'y' || (e.shiftKey && e.key === 'z'))) { ctx.redo(); e.preventDefault(); }
        else if (ctrl && e.key === 'd') { ctx.duplicateSelected(); e.preventDefault(); }
        else if (ctrl && e.key === 'g' && !e.shiftKey) { ctx.groupSelected(); e.preventDefault(); }
        else if (ctrl && e.key === 'g' && e.shiftKey) { ctx.ungroupSelected(); e.preventDefault(); }
        else if (ctrl && e.key === 'a') {
            ctx.setSelected(ctx.elements.filter(el => el.visible && !el.locked).map(el => el.id));
            e.preventDefault();
        }
        else if (ctrl && e.key === 'c') { ctx.copySelected(); e.preventDefault(); }
        else if (ctrl && e.key === 'v') { ctx.paste(); e.preventDefault(); }
        else if (e.key === 'ArrowUp')    { ctx.nudge(0, e.shiftKey ? -10 : -1); e.preventDefault(); }
        else if (e.key === 'ArrowDown')  { ctx.nudge(0, e.shiftKey ? 10 : 1); e.preventDefault(); }
        else if (e.key === 'ArrowLeft')  { ctx.nudge(e.shiftKey ? -10 : -1, 0); e.preventDefault(); }
        else if (e.key === 'ArrowRight') { ctx.nudge(e.shiftKey ? 10 : 1, 0); e.preventDefault(); }
        else if (e.key === 'Escape') {
            if (ctx.isolationGroup) ctx.exitIsolation();
            else ctx.setSelected([]);
        }
    }, opts);
}

// ═══════════════════════════════════════════════
// Context menu
// ═══════════════════════════════════════════════

/**
 * Show the right-click context menu.
 * @param {Event} e — contextmenu event
 * @param {Object} ctx
 */
function showContextMenu(e, ctx) {
    // Skip if inside panels
    const target = razyui(e.target);
    if (target.closest('.le-layers').length || target.closest('.le-props').length) return;

    // Determine clicked element
    const elDom = target.closest('.le-element');
    if (elDom.length) {
        const id = elDom.data('leId');
        const clickedEl = findEl(id, ctx.elements);
        if (clickedEl && !ctx.selected.has(id)) {
            if (ctx.isolationGroup) {
                const parentGroup = findParentGroup(id, ctx.elements);
                if (parentGroup && parentGroup.id === ctx.isolationGroup.id) {
                    ctx.toggleSelect(id, false);
                } else {
                    ctx.toggleSelect(ctx.isolationGroup.id, false);
                }
            } else {
                const parentGroup = findParentGroup(id, ctx.elements);
                ctx.toggleSelect(parentGroup ? parentGroup.id : id, false);
            }
        }
    }

    // Build menu items
    const items = [];
    const selCount = ctx.selected.size;

    if (selCount > 0) {
        items.push({ label: 'Duplicate', shortcut: 'Ctrl+D', action: () => ctx.duplicateSelected() });
        items.push({ label: 'Delete', shortcut: 'Del', action: () => ctx.removeElements([...ctx.selected]) });
        items.push('---');

        if (selCount >= 2) {
            items.push({ label: 'Group', shortcut: 'Ctrl+G', action: () => ctx.groupSelected() });
        }

        const selectedEls = [...ctx.selected].map(id => findEl(id, ctx.elements)).filter(Boolean);
        const hasGroup = selectedEls.some(sel => sel.type === 'group');
        if (hasGroup) {
            items.push({ label: 'Ungroup', shortcut: 'Ctrl+Shift+G', action: () => ctx.ungroupSelected() });
            if (selCount === 1 && selectedEls[0]?.type === 'group') {
                items.push({ label: 'Enter Group', action: () => ctx.enterIsolation(selectedEls[0]) });
            }
        }
        if (ctx.isolationGroup) {
            items.push({ label: 'Exit Group', shortcut: 'Esc', action: () => ctx.exitIsolation() });
        }

        items.push('---');
        items.push({ label: 'Copy', shortcut: 'Ctrl+C', action: () => ctx.copySelected() });
    }

    if (ctx.clipboard.length) {
        items.push({ label: 'Paste', shortcut: 'Ctrl+V', action: () => ctx.paste() });
    }

    if (selCount > 0) {
        items.push('---');
        const selEl = [...ctx.selected].map(id => findEl(id, ctx.elements)).find(Boolean);
        if (selEl) {
            items.push({ label: selEl.locked ? 'Unlock' : 'Lock', action: () => { ctx.pushUndo(); selEl.locked = !selEl.locked; ctx.renderElement(selEl); ctx.refreshLayers(); ctx.onChange(); } });
            items.push({ label: selEl.visible ? 'Hide' : 'Show', action: () => { ctx.pushUndo(); selEl.visible = !selEl.visible; ctx.renderElement(selEl); ctx.refreshLayers(); ctx.onChange(); } });
        }
        items.push('---');
        items.push({ label: 'Bring to front', action: () => ctx.reorderZ('front') });
        items.push({ label: 'Send to back', action: () => ctx.reorderZ('back') });
    }

    if (!items.length) return;

    // Render
    ctx.contextMenuEl.html('');
    items.forEach(item => {
        if (item === '---') {
            const sep = el('div', 'le-ctx-sep');
            ctx.contextMenuEl.append(sep);
            return;
        }
        const row = el('div', 'le-ctx-item');
        row.html(`<span class="le-ctx-label">${item.label}</span>${item.shortcut ? `<span class="le-ctx-shortcut">${item.shortcut}</span>` : ''}`)
           .on('click', () => {
            hideContextMenu(ctx);
            item.action();
        });
        ctx.contextMenuEl.append(row);
    });

    // Position relative to le-body
    const bodyRect = razyui(ctx.container).find('.le-body')[0].getBoundingClientRect();
    let left = e.clientX - bodyRect.left;
    let top  = e.clientY - bodyRect.top;
    ctx.contextMenuEl.removeClass('le-context-hidden');
    ctx.contextMenuEl.css('left', left + 'px');
    ctx.contextMenuEl.css('top', top + 'px');

    // Clamp to body bounds
    requestAnimationFrame(() => {
        const mw = ctx.contextMenuEl.prop('offsetWidth');
        const mh = ctx.contextMenuEl.prop('offsetHeight');
        if (left + mw > bodyRect.width)  left = bodyRect.width - mw - 4;
        if (top + mh > bodyRect.height)  top  = bodyRect.height - mh - 4;
        if (left < 0) left = 4;
        if (top < 0)  top  = 4;
        ctx.contextMenuEl.css('left', left + 'px');
        ctx.contextMenuEl.css('top', top + 'px');
    });

    // Auto-hide on next click (use AbortController for cleanup on destroy)
    const hideAC = new AbortController();
    const hide = (ev) => {
        if (ctx.contextMenuEl.contains(ev.target)) return;
        hideContextMenu(ctx);
        hideAC.abort();
    };
    if (ctx.signal) ctx.signal.addEventListener('abort', () => hideAC.abort());
    setTimeout(() => document.addEventListener('pointerdown', hide, { capture: true, signal: hideAC.signal }), 0);
}

/**
 * Hide the context menu.
 * @param {Object} ctx
 */
function hideContextMenu(ctx) {
    ctx.contextMenuEl.addClass('le-context-hidden');
}

// ═══════════════════════════════════════════════
// Delegated view events
// ═══════════════════════════════════════════════

/**
 * Bind all delegated view-level events (layer panel, props panel,
 * palette, isolation bar, and text-content input).
 *
 * Called once during construction — replaces per-element listeners
 * that were previously attached inside view.js render functions.
 * @param {Object} ctx
 */
export function bindViewDelegation(ctx) {
    const propBody = ctx.propPanel.find('.le-prop-body');

    // ── Text-content input on artboard ──────────────────────
    ctx.artboard.on('input', (e) => {
        const content = razyui(e.target).closest('.le-text-content[contenteditable="true"]');
        if (!content.length) return;
        const elDom = content.closest('.le-element');
        if (!elDom.length) return;
        const elData = findEl(elDom.data('leId'), ctx.elements);
        if (elData) {
            elData.content = content[0].textContent;
            ctx.onChange();
        }
    });

    // ── Layer list delegation ───────────────────────────────────
    const layerList = ctx.layerPanel.find('.le-layer-list');

    layerList.on('click', (e) => {
        const row = razyui(e.target).closest('.le-layer-row');
        if (!row.length) return;
        const id = row.data('leId');
        const elData = findEl(id, ctx.elements);
        if (!elData) return;

        if (razyui(e.target).hasClass('le-layer-group-toggle')) {
            if (ctx.collapsedGroups.has(id)) ctx.collapsedGroups.delete(id);
            else ctx.collapsedGroups.add(id);
            ctx.refreshLayers();
            return;
        }
        if (razyui(e.target).hasClass('le-layer-vis')) {
            elData.visible = !elData.visible;
            ctx.renderElement(elData);
            ctx.refreshLayers();
            ctx.onChange();
            return;
        }
        if (razyui(e.target).hasClass('le-layer-lock')) {
            elData.locked = !elData.locked;
            ctx.renderElement(elData);
            ctx.refreshLayers();
            ctx.onChange();
            return;
        }
        ctx.toggleSelect(id, e.shiftKey || e.ctrlKey || e.metaKey);
    });

    layerList.on('dragstart', (e) => {
        const row = e.target.closest('.le-layer-row');
        if (!row) return;
        e.dataTransfer.setData('text/plain', row.dataset.leId);
        razyui(row).addClass('le-layer-dragging');
    });

    layerList.on('dragend', (e) => {
        const row = e.target.closest('.le-layer-row');
        if (row) razyui(row).removeClass('le-layer-dragging');
    });

    layerList.on('dragover', (e) => {
        const row = e.target.closest('.le-layer-row');
        if (row) {
            e.preventDefault();
            razyui(row).addClass('le-layer-dragover');
        }
    });

    layerList.on('dragleave', (e) => {
        const row = e.target.closest('.le-layer-row');
        if (row) razyui(row).removeClass('le-layer-dragover');
    });

    layerList.on('drop', (e) => {
        const row = e.target.closest('.le-layer-row');
        if (!row) return;
        e.preventDefault();
        razyui(row).removeClass('le-layer-dragover');
        const fromId = e.dataTransfer.getData('text/plain');
        ctx.reorderLayer(fromId, row.dataset.leId);
    });

    // ── Props panel delegation (artboard + element props) ──────
    propBody.on('change', (e) => {
        const input = e.target;
        const artboard = input.dataset.artboard;
        if (artboard) {
            if (artboard === 'preset') {
                if (input.value === 'custom') return;
                const [pw, ph] = input.value.split('x').map(Number);
                ctx.setArtboardDims(pw, ph);
                const wInput = propBody.find('[data-artboard="w"]');
                const hInput = propBody.find('[data-artboard="h"]');
                if (wInput.length) wInput.val(pw);
                if (hInput.length) hInput.val(ph);
            } else if (artboard === 'w') {
                ctx.setArtboardDims(parseInt(input.value) || ctx.artboardW, ctx.artboardH);
                const preset = propBody.find('[data-artboard="preset"]');
                if (preset.length) preset.val('custom');
            } else if (artboard === 'h') {
                ctx.setArtboardDims(ctx.artboardW, parseInt(input.value) || ctx.artboardH);
                const preset = propBody.find('[data-artboard="preset"]');
                if (preset.length) preset.val('custom');
            } else if (artboard === 'grid') {
                ctx.gridSize = Math.max(5, parseInt(input.value) || 20);
                const gridOvl = ctx.artboard.find('.le-grid-overlay');
                if (gridOvl.length) gridOvl.css('background-size', `${ctx.gridSize}px ${ctx.gridSize}px`);
            } else if (artboard === 'snap-grid') {
                ctx.snapToGrid = input.checked;
            } else if (artboard === 'snap-guides') {
                ctx.snapGuides = input.checked;
            }
            return;
        }

        // Element props
        const prop = input.dataset.prop;
        const styleProp = input.dataset.styleProp;
        if (!prop && !styleProp) return;
        if (ctx.selected.size !== 1) return;
        const elData = findEl([...ctx.selected][0], ctx.elements);
        if (!elData) return;

        if (styleProp) {
            ctx.pushUndo();
            elData.style[styleProp] = input.value;
            const parent = razyui(input).parent();
            const $swatch = parent.find('.le-prop-color-swatch');
            if ($swatch.length) $swatch.css('background', input.value || 'transparent');
            const slider = parent.find(`.le-prop-slider[data-slider-for="${styleProp}"]`)[0];
            if (slider) slider.value = parseFloat(input.value) || 0;
            ctx.renderElement(elData);
            ctx.onChange();
        } else if (prop) {
            ctx.pushUndo();
            const val = ['x','y','w','h','rotation'].includes(prop) ? parseFloat(input.value) || 0 : input.value;
            elData[prop] = val;
            const parent = razyui(input).parent();
            const slider = parent.find(`.le-prop-slider[data-slider-for="${prop}"]`)[0];
            if (slider) slider.value = val;
            ctx.renderElement(elData);
            ctx.refreshLayers();
            ctx.onChange();
        }
    });

    propBody.on('input', (e) => {
        const slider = razyui(e.target).closest('.le-prop-slider');
        if (!slider.length) return;
        if (ctx.selected.size !== 1) return;
        const elData = findEl([...ctx.selected][0], ctx.elements);
        if (!elData) return;

        const forProp = slider.data('sliderFor');
        const isStyle = slider.data('sliderStyle') === '1';
        const numInput = slider.parent().find('.le-prop-slider-num')[0];
        if (isStyle) {
            const suffix = forProp === 'borderRadius' ? 'px' : (forProp === 'fontSize' ? 'px' : '');
            const val = suffix ? slider[0].value + suffix : (forProp === 'opacity' ? slider[0].value : slider[0].value);
            elData.style[forProp] = val;
            if (numInput) numInput.value = val;
        } else {
            const val = parseFloat(slider[0].value) || 0;
            elData[forProp] = val;
            if (numInput) numInput.value = val;
        }
        ctx.renderElement(elData);
        ctx.onChange();
    });

    propBody.on('pointerdown', (e) => {
        if (e.target.closest('.le-prop-slider')) ctx.pushUndo();
    });

    propBody.on('click', (e) => {
        const group = e.target.closest('.le-prop-btngroup');
        if (!group) return;
        const btn = e.target.closest('.le-prop-btn');
        const styleProp = group.dataset.styleProp;
        if (!btn || !styleProp) return;
        if (ctx.selected.size !== 1) return;
        const elData = findEl([...ctx.selected][0], ctx.elements);
        if (!elData) return;

        ctx.pushUndo();
        elData.style[styleProp] = btn.dataset.val;
        razyui(group).find('.le-prop-btn').each(b => razyui(b).removeClass('le-prop-btn-active'));
        razyui(btn).addClass('le-prop-btn-active');
        ctx.renderElement(elData);
        ctx.onChange();
    });

    // ── Palette delegation ──────────────────────────────────────
    const paletteList = ctx.palettePanel.find('.le-palette-list');

    paletteList.on('dragstart', (e) => {
        const chip = e.target.closest('.le-palette-item');
        if (!chip) return;
        const pType = chip.dataset.paletteType;
        const pName = chip.dataset.paletteName;
        if (pType === 'plugin') {
            e.dataTransfer.setData('text/le-plugin', pName);
        } else {
            e.dataTransfer.setData('text/le-element', pName);
        }
        e.dataTransfer.effectAllowed = 'copy';
    });

    paletteList.on('click', (e) => {
        const chip = e.target.closest('.le-palette-item');
        if (!chip) return;
        const pType = chip.dataset.paletteType;
        const pName = chip.dataset.paletteName;
        if (pType === 'plugin') {
            const plugin = ctx.plugins.find(p => p.name === pName);
            if (plugin) ctx.addPluginElement(plugin);
        } else {
            const center = ctx.viewportCenter();
            ctx.addElement(pName, { x: center.x - 60, y: center.y - 30 });
        }
    });

    // ── Isolation bar delegation (from canvas) ──────────────────
    ctx.canvas.on('click', (e) => {
        if (e.target.closest('.le-iso-exit') || e.target.closest('.le-iso-breadcrumb')) {
            ctx.exitIsolation();
        }
    });
}
